const body = $input.first().json.body || $input.first().json;
const headers = $input.first().json.headers || {};

// Detect source
let source = body.source || body.type?.split('.')[0] || 'unknown';
if (headers['x-github-event']) source = 'github';
else if (headers['stripe-signature']) source = 'stripe';
else if (body.zap_name) source = 'zapier';
else if (body.workflow) source = 'n8n';
else if (body.event_type?.startsWith('consent')) source = 'consent';
else if (body.session_id && body.filename) source = 'voice';
else if (body.model || body.crew_member) source = 'dreamchamber';

return [{ json: { ...body, _source: source, _headers: headers, _ts: new Date().toISOString() } }];

const e = $input.first().json;
const event = e._headers?.['x-github-event'] || 'unknown';
const actions = {
  push: () => `${e.pusher?.name || 'unknown'} pushed ${e.commits?.length || 0} commit(s) to ${e.ref?.replace('refs/heads/','')}`,
  pull_request: () => `PR #${e.number} ${e.action}: ${e.pull_request?.title}`,
  release: () => `Release ${e.action}: ${e.release?.tag_name}`,
  issues: () => `Issue #${e.issue?.number} ${e.action}: ${e.issue?.title}`,
  workflow_run: () => `Workflow "${e.workflow_run?.name}" ${e.action}`
};
const summary = actions[event]?.() || `GitHub: ${event}`;
return [{ json: { source:'github', event, summary, repo: e.repository?.full_name, ts: e._ts } }];

const e = $input.first().json;
const eventType = e.type || 'unknown';
const data = e.data?.object || {};
const summaries = {
  'payment_intent.succeeded': `Payment: $${((data.amount||0)/100).toFixed(2)}`,
  'invoice.paid': `Invoice paid: $${((data.amount_paid||0)/100).toFixed(2)}`,
  'customer.subscription.created': `New sub: ${data.plan?.nickname || data.id}`,
  'customer.subscription.deleted': `Sub cancelled: ${data.id}`,
  'checkout.session.completed': `Checkout: $${((data.amount_total||0)/100).toFixed(2)}`
};
const summary = summaries[eventType] || `Stripe: ${eventType}`;
return [{ json: { source:'stripe', event:eventType, summary, livemode:e.livemode, ts:e._ts } }];

const e = $input.first().json;
const eventType = e.event_type || 'consent.update';
const summary = `Consent ${eventType}: actor ${e.actor_id || 'unknown'}`;
return [{ json: { source:'consent', event:eventType, summary, actor_id:e.actor_id, token_id:e.token_id, action:e.action, ts:e._ts } }];

const e = $input.first().json;
const eventType = e.event || 'recording.complete';
const summary = `Voice ${eventType}: ${e.filename || e.session_id || 'session'}`;
return [{ json: { source:'voice', event:eventType, summary, session_id:e.session_id, filename:e.filename, duration:e.duration, ts:e._ts } }];

const e = $input.first().json;
const eventType = e.event || 'session.update';
const summary = `DreamChamber ${eventType}: ${e.model || e.crew_member || 'GABRIEL'}`;
return [{ json: { source:'dreamchamber', event:eventType, summary, model:e.model, crew_member:e.crew_member, session_id:e.session_id, ts:e._ts } }];

const e = $input.first().json;
const summary = e.summary || `Custom: ${e._source} / ${e.event || 'trigger'}`;
return [{ json: { source: e._source || 'custom', event: e.event || 'trigger', summary, payload: e, ts: e._ts } }];

// Merge all handler outputs into single enriched event
const event = $input.first().json;
return [{ json: {
  ...event,
  enriched_at: new Date().toISOString(),
  empire_version: '17.7.0',
  dispatch_to: ['heaven_ledger', 'gabriel_memcell']
} }];

const heaven = $input.all()[0]?.json || {};
const gabriel = $input.all()[1]?.json || {};
const ts = new Date().toISOString();
const allOk = heaven.status === 'LIVE' && gabriel.ok === true;
return [{ json: { ts, heaven_status: heaven.status, heaven_version: heaven.version, gabriel_model: gabriel.model, gabriel_uptime: gabriel.uptime, all_ok: allOk } }];
